select

from tb_announcement


    and title like concat('%', #{title}, '%')


    and content like concat('%', #{content}, '%')


    and is_top = #{isTop,jdbcType=TINYINT}


    and create_time between #{createTime.start} and #{createTime.end}


    and update_time between #{updateTime.start} and #{updateTime.end}


order by update_time desc

